/**
 * Interactive word search grid for the Play tab.
 *
 * Unlike the crossword grid, word search:
 * - Shows ALL letters (placed words + random fill)
 * - Player clicks start cell, then clicks end cell to select a word path
 * - Found words are highlighted with distinct colors
 * - No typing — this is a search, not a fill
 */

import { useState, useMemo, useCallback, useRef } from 'react';
import type { CrosswordResult, DirectionalWord } from '../../logic/types';
import { getWordCellCoords, getWordVector } from '../../logic/wordSearchGenerator';
import { CompletionConfetti } from '../CompletionConfetti';
import { WordCircleOverlay } from './WordCircleOverlay';
import { WORD_CIRCLE_COLORS } from '../../utils/wordCircleColors';
import {
  GRID_PAN,
  GRID_PAGE,
  GRID_FRAME,
  CELL_BASE,
  CELL_LETTER,
  LETTER_FONT_SIZE,
  gridSizingStyle,
} from './gridStyles';

function cellKey(x: number, y: number): string {
  return x + ',' + y;
}

interface WordSearchGridProps {
  puzzle: CrosswordResult;
}

interface FoundWord {
  word: DirectionalWord;
  cells: string[];  // cellKey strings
  colorIndex: number;
}

export function WordSearchGrid({ puzzle }: WordSearchGridProps) {
  const [foundWords, setFoundWords] = useState<FoundWord[]>([]);
  const [startCell, setStartCell] = useState<{ x: number; y: number } | null>(null);
  const [hoverCell, setHoverCell] = useState<{ x: number; y: number } | null>(null);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [announcement, setAnnouncement] = useState('');
  const [lastFoundAnim, setLastFoundAnim] = useState<string | null>(null);
  const timerRef = useRef<number | null>(null);

  const isComplete = foundWords.length === puzzle.wordLocations.length;

  // Timer
  const startTimer = useCallback(() => {
    if (isTimerRunning || isComplete) return;
    setIsTimerRunning(true);
    timerRef.current = window.setInterval(() => {
      setElapsedSeconds(prev => prev + 1);
    }, 1000);
  }, [isTimerRunning, isComplete]);

  const stopTimer = useCallback(() => {
    setIsTimerRunning(false);
    if (timerRef.current !== null) {
      clearInterval(timerRef.current);
      timerRef.current = null;
    }
  }, []);

  // Build a map of cellKey -> found word color index
  const foundCellMap = useMemo(() => {
    const map = new Map<string, number>();
    for (const fw of foundWords) {
      for (const ck of fw.cells) {
        map.set(ck, fw.colorIndex);
      }
    }
    return map;
  }, [foundWords]);

  // Build a set of already found word strings
  const foundWordSet = useMemo(() => {
    return new Set(foundWords.map(fw => fw.word.word));
  }, [foundWords]);

  // Compute preview line cells when dragging
  const previewCells = useMemo(() => {
    if (!startCell || !hoverCell) return new Set<string>();
    return getCellsBetween(startCell.x, startCell.y, hoverCell.x, hoverCell.y, puzzle.width, puzzle.height);
  }, [startCell, hoverCell, puzzle.width, puzzle.height]);

  // Check if a selection matches any unfound word
  const checkSelection = useCallback((sx: number, sy: number, ex: number, ey: number) => {
    const selectedCells = getCellsBetween(sx, sy, ex, ey, puzzle.width, puzzle.height);
    if (selectedCells.size === 0) return;

    // Build the selected string from grid
    const cellArr = Array.from(selectedCells);
    // We need ordered cells to build the string
    const orderedCells = getOrderedCells(sx, sy, ex, ey);
    const selectedStr = orderedCells.map(([cx, cy]) => puzzle.grid[cy][cx]).join('');
    const reversedStr = selectedStr.split('').reverse().join('');

    for (const wordLoc of puzzle.wordLocations) {
      if (foundWordSet.has(wordLoc.word)) continue;

      if (wordLoc.word === selectedStr || wordLoc.word === reversedStr) {
        const colorIndex = foundWords.length % WORD_CIRCLE_COLORS.length;
        const newFound: FoundWord = {
          word: wordLoc,
          cells: cellArr,
          colorIndex,
        };
        const updated = [...foundWords, newFound];
        setFoundWords(updated);
        setAnnouncement(`Found: ${(wordLoc.displayWord ?? wordLoc.word).toUpperCase()}, ${puzzle.wordLocations.length - updated.length} remaining`);
        setLastFoundAnim(wordLoc.word);
        setTimeout(() => setLastFoundAnim(null), 500);

        // Check completion
        if (updated.length === puzzle.wordLocations.length) {
          stopTimer();
        }
        return;
      }
    }
  }, [puzzle, foundWords, foundWordSet, stopTimer]);

  function handleCellClick(x: number, y: number) {
    startTimer();

    if (!startCell) {
      setStartCell({ x, y });
    } else {
      // Complete the selection
      checkSelection(startCell.x, startCell.y, x, y);
      setStartCell(null);
      setHoverCell(null);
    }
  }

  function handleCellHover(x: number, y: number) {
    if (startCell) {
      setHoverCell({ x, y });
    }
  }

  // Escape to cancel selection
  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'Escape' && startCell) {
      setStartCell(null);
      setHoverCell(null);
    }
  }

  function handleReset() {
    setFoundWords([]);
    setStartCell(null);
    setHoverCell(null);
    setElapsedSeconds(0);
    setIsTimerRunning(false);
    setLastFoundAnim(null);
    if (timerRef.current !== null) {
      clearInterval(timerRef.current);
      timerRef.current = null;
    }
  }

  function handleReveal() {
    const allFound: FoundWord[] = puzzle.wordLocations.map((wl, i) => {
      const cells = getWordCells(wl);
      return { word: wl, cells, colorIndex: i % WORD_CIRCLE_COLORS.length };
    });
    setFoundWords(allFound);
    stopTimer();
  }

  const formatTime = (s: number) => {
    const mins = Math.floor(s / 60);
    const secs = s % 60;
    return String(mins).padStart(2, '0') + ':' + String(secs).padStart(2, '0');
  };

  return (
    <div className="animate-fade-in">
      {/* Completion — same editorial moment as the crossword */}
      {isComplete && (
        <div className="mb-6 px-6 py-8 warm-card text-center animate-slide-up relative overflow-hidden">
          <CompletionConfetti />
          <div className="relative z-10">
            <p className="font-display text-4xl text-ink" style={{ fontVariationSettings: "'SOFT' 40" }}>
              All found.
            </p>
            <div className="mx-auto mt-3 mb-2.5 w-10 border-t-2 border-rubric" aria-hidden="true" />
            <p className="text-ink-2 text-sm tabular-nums">
              {formatTime(elapsedSeconds)}
            </p>
          </div>
        </div>
      )}

      <div className="flex flex-col lg:flex-row gap-6">
        {/* Left: Grid + Controls */}
        <div className="flex-shrink-0">
          {/* Solving desk strip — same bound toolbar as the crossword */}
          <div className="flex flex-wrap items-center justify-between gap-x-4 gap-y-2 mb-4
                          rounded-md border border-line bg-card shadow-paper px-3 py-2">
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="font-mono text-lg font-semibold text-ink tabular-nums">
                  {formatTime(elapsedSeconds)}
                </span>
                {isTimerRunning && (
                  <span className="w-2 h-2 rounded-full bg-rubric animate-pulse" />
                )}
              </div>
              {/* Progress — ink filling a rule */}
              <div className="flex items-center gap-1.5">
                <div className="w-16 h-1.5 bg-well rounded-full overflow-hidden">
                  <div
                    className="h-full bg-accent rounded-full transition-all duration-500 ease-out"
                    style={{ width: `${puzzle.wordLocations.length > 0 ? (foundWords.length / puzzle.wordLocations.length) * 100 : 0}%` }}
                  />
                </div>
                <span className="text-xs text-ink-3 font-mono tabular-nums">
                  {foundWords.length}/{puzzle.wordLocations.length}
                </span>
              </div>
            </div>
            <div className="flex items-center gap-1.5">
              <button
                onClick={handleReveal}
                className="btn-ghost btn-sm text-accent hover:bg-accent/10 hover:text-accent"
              >
                Reveal
              </button>
              <button onClick={handleReset} className="btn-ghost btn-sm">
                Reset
              </button>
            </div>
          </div>

          {/* Selection hint */}
          <div className="mb-3 text-xs text-ink-3">
            {startCell
              ? <span>Click the <span className="font-medium text-rubric">end cell</span> to complete selection</span>
              : <span>Click a cell to <span className="font-medium text-rubric">start selecting</span> a word</span>
            }
          </div>

          {/* Grid — pans horizontally on phones instead of crushing cells.
              Print treatment from gridStyles: paper cells, INK letters in
              every theme (the old stone-300 letters vanished on the light
              paper in dark mode). */}
          <div className={`${GRID_PAN} pb-2`}>
          <div className={GRID_PAGE} tabIndex={0} onKeyDown={handleKeyDown} style={{ outline: 'none' }}>
            <div
              role="grid"
              aria-label="Word search puzzle grid"
              className={`relative ${GRID_FRAME}`}
              style={gridSizingStyle(puzzle.width, 30, 44)}
            >
              {puzzle.grid.map((row, y) =>
                row.map((cell, x) => {
                  const key = cellKey(x, y);
                  const isFound = foundCellMap.has(key);
                  const isStart = startCell !== null && startCell.x === x && startCell.y === y;
                  const isPreview = previewCells.has(key);

                  return (
                    <div
                      key={key}
                      role="gridcell"
                      aria-label={`Row ${y + 1}, Column ${x + 1}, letter ${cell.toUpperCase()}${isFound ? ', found' : ''}`}
                      onClick={() => handleCellClick(x, y)}
                      onMouseEnter={() => handleCellHover(x, y)}
                      className={`
                        ${CELL_BASE} cursor-pointer transition-all duration-100
                        ${isPreview ? 'bg-primary-100' : 'bg-grid-cell dark:bg-grid-cell-dark hover:bg-primary-50'}
                        ${isStart ? 'ring-2 ring-primary-500 z-10' : ''}
                      `}
                    >
                      <span className={CELL_LETTER} style={{ fontSize: LETTER_FONT_SIZE }}>
                        {cell}
                      </span>
                    </div>
                  );
                })
              )}

              {/* Found words get a real marker circle, exactly like the
                  printed answer key — not a cell-by-cell tint. */}
              <WordCircleOverlay
                words={foundWords.map(fw => fw.word)}
                gridWidth={puzzle.width}
                gridHeight={puzzle.height}
                colorIndexFor={(_, i) => foundWords[i].colorIndex}
                withFill={true}
              />
            </div>
          </div>
          </div>
        </div>

        {/* Right: Word List */}
        <div className="flex-1 min-w-0">
          <WordList
            words={puzzle.wordLocations}
            foundWords={foundWords}
            lastFoundWord={lastFoundAnim}
          />
        </div>
      </div>

      {/* Screen reader announcements */}
      <div aria-live="polite" className="sr-only">{announcement}</div>
    </div>
  );
}

/**
 * Word list showing all words to find, with found words struck through.
 */
function WordList({ words, foundWords, lastFoundWord }: {
  words: DirectionalWord[];
  foundWords: FoundWord[];
  lastFoundWord: string | null;
}) {
  const foundSet = new Set(foundWords.map(fw => fw.word.word));
  const foundMap = new Map(foundWords.map(fw => [fw.word.word, fw]));

  return (
    <div className="warm-card p-4">
      <h3 className="section-label mb-3">
        Words to find
      </h3>

      <div className="space-y-3">
        {groupWordsByDirection(words).map(({ label, items }) => (
          <div key={label}>
            <h4 className="sub-label mb-1.5">{label}</h4>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-1">
              {items.map((wl) => {
                const isFound = foundSet.has(wl.word);
                const fw = foundMap.get(wl.word);
                const color = fw ? WORD_CIRCLE_COLORS[fw.colorIndex % WORD_CIRCLE_COLORS.length] : null;
                const isJustFound = lastFoundWord === wl.word;

                return (
                  <div
                    key={wl.word + wl.x + wl.y}
                    className={`
                      flex items-center gap-2 px-2.5 py-1.5 rounded-lg transition-all duration-200
                      ${isFound ? 'opacity-75' : 'opacity-100'}
                      ${isJustFound ? 'animate-word-found' : ''}
                    `}
                  >
                    <div
                      className={`w-2 h-2 rounded-full flex-shrink-0 transition-all duration-200 ${
                        isFound ? '' : 'bg-line-2'
                      }`}
                      style={isFound && color ? { backgroundColor: color } : undefined}
                    />
                    <span className={`text-sm font-medium uppercase tracking-wide ${
                      isFound
                        ? 'line-through text-ink-3'
                        : 'text-ink'
                    }`}>
                      {wl.displayWord ?? wl.word}
                    </span>
                    <span className={`text-xs truncate ${
                      isFound ? 'text-ink-3/60' : 'text-ink-3'
                    }`}>
                      {wl.clue}
                    </span>
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

/**
 * Group words by their placement direction for display.
 * Uses the exact vector — the flags alone mislabel diagonals as Down.
 */
function getDirectionLabel(wl: DirectionalWord): string {
  const { dx, dy } = getWordVector(wl);
  if (dy === 0) return 'Across';
  if (dx === 0) return 'Down';
  return 'Diagonal';
}

function groupWordsByDirection(words: DirectionalWord[]): { label: string; items: DirectionalWord[] }[] {
  const groups = new Map<string, DirectionalWord[]>();
  for (const wl of words) {
    const label = getDirectionLabel(wl);
    const existing = groups.get(label);
    if (existing) {
      existing.push(wl);
    } else {
      groups.set(label, [wl]);
    }
  }
  return Array.from(groups.entries()).map(([label, items]) => ({ label, items }));
}

/**
 * Get the set of cell keys between two points in a valid line (8 directions).
 * Returns empty set if the line is not a valid 8-direction line.
 */
function getCellsBetween(
  x1: number, y1: number, x2: number, y2: number,
  width: number, height: number
): Set<string> {
  const cells = new Set<string>();
  const dx = x2 - x1;
  const dy = y2 - y1;

  // Must be horizontal, vertical, or 45-degree diagonal
  if (dx !== 0 && dy !== 0 && Math.abs(dx) !== Math.abs(dy)) return cells;
  if (dx === 0 && dy === 0) {
    cells.add(cellKey(x1, y1));
    return cells;
  }

  const steps = Math.max(Math.abs(dx), Math.abs(dy));
  const stepX = dx === 0 ? 0 : dx / Math.abs(dx);
  const stepY = dy === 0 ? 0 : dy / Math.abs(dy);

  for (let i = 0; i <= steps; i++) {
    const cx = x1 + i * stepX;
    const cy = y1 + i * stepY;
    if (cx < 0 || cx >= width || cy < 0 || cy >= height) return new Set();
    cells.add(cellKey(cx, cy));
  }

  return cells;
}

/**
 * Get ordered array of [x,y] cells between two points.
 */
function getOrderedCells(x1: number, y1: number, x2: number, y2: number): [number, number][] {
  const cells: [number, number][] = [];
  const dx = x2 - x1;
  const dy = y2 - y1;

  if (dx !== 0 && dy !== 0 && Math.abs(dx) !== Math.abs(dy)) return cells;

  const steps = Math.max(Math.abs(dx), Math.abs(dy));
  if (steps === 0) {
    cells.push([x1, y1]);
    return cells;
  }

  const stepX = dx / Math.abs(dx || 1);
  const stepY = dy / Math.abs(dy || 1);

  for (let i = 0; i <= steps; i++) {
    cells.push([x1 + i * stepX, y1 + i * stepY]);
  }

  return cells;
}

/**
 * Get all cells occupied by a placed word — exact, from the stored
 * direction vector (with a flags fallback for old crossword-style data).
 */
function getWordCells(wl: DirectionalWord): string[] {
  return getWordCellCoords(wl).map(({ x, y }) => cellKey(x, y));
}
